changeSet.sql:
DO $$ DECLARE t text; tables text[] := ARRAY[ 'customers', 'customer_balances', 'customer_credits', 'document_number_sequences', 'quotes', 'quote_lines', 'orders', 'order_lines', 'invoices', 'invoice_lines', 'credit_notes', 'deliveries', 'delivery_lines', 'payments' ]; BEGIN FOREACH t IN ARRAY tables LOOP EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY', t); EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY', t);
EXECUTE format('DROP POLICY IF EXISTS tenant_isolation_select ON %I', t); EXECUTE format( 'CREATE POLICY tenant_isolation_select ON %I FOR SELECT USING (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL)', t);
EXECUTE format('DROP POLICY IF EXISTS tenant_isolation_modify ON %I', t); EXECUTE format( 'CREATE POLICY tenant_isolation_modify ON %I FOR ALL USING (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL) WITH CHECK (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL)', t); END LOOP; END $$;
